
$(document).ready(function(){
    $(".All").click(function(){
        $(".MobileApp").fadeIn();
        $(".Website").fadeIn();
        $(".DevelopmentLibrary").fadeIn();
        $(".DevelopmentTool").fadeIn();
        $(".MacApp").fadeIn();
    });
    $(".MacButton").click(function(){
        $(".MobileApp").fadeOut();
        $(".Website").fadeOut();
        $(".DevelopmentLibrary").fadeOut();
        $(".DevelopmentTool").fadeOut();
        $(".MacApp").fadeIn();
    });
    $(".MobileAppButton").click(function(){
        $(".MobileApp").fadeIn();
        $(".Website").fadeOut();
        $(".DevelopmentLibrary").fadeOut();
        $(".DevelopmentTool").fadeOut();
        $(".MacApp").fadeOut();
    });
    $(".WebsiteButton").click(function(){
        $(".MobileApp").fadeOut();
        $(".Website").fadeIn();
        $(".DevelopmentLibrary").fadeOut();
        $(".DevelopmentTool").fadeOut();
        $(".MacApp").fadeOut();
    });
    $(".DevelopmentLibraryButton").click(function(){
        $(".MobileApp").fadeOut();
        $(".Website").fadeOut();
        $(".DevelopmentLibrary").fadeIn();
        $(".DevelopmentTool").fadeOut();
        $(".MacApp").fadeOut();
    });       
    $(".DevelopmentToolButton").click(function(){
        $(".MobileApp").fadeOut();
        $(".Website").fadeOut();
        $(".DevelopmentLibrary").fadeOut();
        $(".DevelopmentTool").fadeIn();
        $(".MacApp").fadeOut();
    }); 
    const urlParams = new URLSearchParams(window.location.search);
    const typeParam = urlParams.get('type');
    console.log(typeParam);
    if (typeParam != null && typeParam != "")
    {
        $(".MobileApp").fadeOut();
        $(".Website").fadeOut();
        $(".DevelopmentLibrary").fadeOut();
        $(".DevelopmentTool").fadeOut();
        $(".MacApp").fadeOut();
        $(typeParam).fadeIn();
    }  
});